<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Box</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">WriteFileTool</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">base_dir</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clone</span><span style="color:#9399B2;">())),</span></span>
